const allItems = $input.all();

const originalData = allItems[0].json;
const facebookPost = allItems[1].json;
const instagramPost = allItems[2].json;

// Check both posts succeeded
const facebookSuccess = facebookPost.post_id !== undefined;
const instagramSuccess = instagramPost.id !== undefined && facebookPost.post_id === undefined ? false : instagramPost.id !== undefined;

// Facebook has both id and post_id, Instagram only has id
const bothSucceeded = facebookPost.post_id !== undefined && instagramPost.id !== undefined;

if (!bothSucceeded) {
  throw new Error(`Posting failed! Facebook: ${facebookSuccess ? 'OK' : 'FAILED'}, Instagram: ${instagramSuccess ? 'OK' : 'FAILED'}`);
}

return {
  json: {
    row_number: originalData.row_number,
    facebook_post_id: facebookPost.post_id,
    instagram_post_id: instagramPost.id,
    status: "posted successfully"
  }
};

